// friday13.cs — Friday the 13th in the proleptic Gregorian calendar

// Find the earliest Friday the 13th starting from 0001-01-01
var date = new DateTime(1, 1, 13); // start checking the 13th of each month
DateTime? earliest = null;

while (date.Year <= 400)
{
    if (date.DayOfWeek == DayOfWeek.Friday)
    {
        earliest ??= date;
        break;
    }
    date = date.AddMonths(1);
}

Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd}");
Console.WriteLine();

// Count all Friday the 13ths in a full 400-year cycle (0001-01-01 to 0400-12-31)
// The Gregorian calendar repeats every 400 years exactly.
int count = 0;
date = new DateTime(1, 1, 13);
while (date.Year <= 400)
{
    if (date.DayOfWeek == DayOfWeek.Friday)
        count++;
    date = date.AddMonths(1);
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"That's an average of {count / 400.0:F2} per year, or {count / 4800.0:F4} per month");
Console.WriteLine();

// Bonus: which day of the week is the 13th most likely to fall on?
var dayCounts = new int[7];
date = new DateTime(1, 1, 13);
while (date.Year <= 400)
{
    dayCounts[(int)date.DayOfWeek]++;
    date = date.AddMonths(1);
}

Console.WriteLine("Distribution of the 13th by day of week (400-year cycle):");
foreach (DayOfWeek day in Enum.GetValues<DayOfWeek>())
{
    Console.WriteLine($"  {day,-10} {dayCounts[(int)day],4}");
}

